const DEFAULT_BATCH_WINDOW_IN_MS = 16;
const SLOW_BATCH_WINDOW_IN_MS = 32;
const SLOW_FLUSH_THRESHOLD_IN_MS = 24;

type AIStreamBatchTimer = ReturnType<typeof setTimeout>;
type AIStreamBatchFlushOptions = {
  force?: boolean;
};

export type AIStreamBatcher = ReturnType<typeof createAIStreamBatcher>;

export function shouldFlushAIStreamChunkImmediately(chunk: string) {
  return chunk.includes('\n') || chunk.includes('```') || chunk.includes('|');
}

export function createAIStreamBatcher({
  applyChunk,
  cancel = clearTimeout,
  getNow = () => performance.now(),
  schedule = setTimeout,
}: {
  applyChunk: (chunk: string, options?: AIStreamBatchFlushOptions) => void;
  cancel?: (timer: AIStreamBatchTimer) => void;
  getNow?: () => number;
  schedule?: (callback: () => void, delayInMs: number) => AIStreamBatchTimer;
}) {
  let batchWindowInMs = DEFAULT_BATCH_WINDOW_IN_MS;
  let pendingChunk = '';
  let timer: AIStreamBatchTimer | null = null;

  const clearTimer = () => {
    if (timer) {
      cancel(timer);
      timer = null;
    }
  };

  const flush = (options?: AIStreamBatchFlushOptions) => {
    if (!pendingChunk) return false;

    const chunk = pendingChunk;

    pendingChunk = '';
    clearTimer();

    const startedAt = getNow();

    applyChunk(chunk, options);

    batchWindowInMs =
      getNow() - startedAt > SLOW_FLUSH_THRESHOLD_IN_MS
        ? SLOW_BATCH_WINDOW_IN_MS
        : DEFAULT_BATCH_WINDOW_IN_MS;

    return true;
  };

  const queue = ({ chunk, isFirst }: { chunk: string; isFirst: boolean }) => {
    if (!chunk) return;

    if (isFirst) {
      reset();
      pendingChunk = chunk;
      flush();

      return;
    }

    pendingChunk += chunk;

    if (shouldFlushAIStreamChunkImmediately(chunk)) {
      flush();

      return;
    }

    if (!timer) {
      timer = schedule(() => {
        timer = null;
        flush();
      }, batchWindowInMs);
    }
  };

  const reset = () => {
    pendingChunk = '';
    batchWindowInMs = DEFAULT_BATCH_WINDOW_IN_MS;
    clearTimer();
  };

  return {
    flush,
    getBatchWindowInMs: () => batchWindowInMs,
    getPendingChunk: () => pendingChunk,
    queue,
    reset,
  };
}

'use client';

import { useEffect, useRef } from 'react';

import cloneDeep from 'lodash/cloneDeep.js';
import { BaseAIPlugin, withAIBatch } from '@platejs/ai';
import {
  AIChatPlugin,
  AIPlugin,
  applyAISuggestions,
  getInsertPreviewStart,
  resetStreamInsertChunk,
  streamInsertChunk,
  useChatChunk,
} from '@platejs/ai/react';
import { ElementApi, getPluginType, KEYS, PathApi } from 'platejs';
import { usePluginOption } from 'platejs/react';

import { AILoadingBar, AIMenu } from '@/registry/ui/ai-menu';
import { AIAnchorElement, AILeaf } from '@/registry/ui/ai-node';
import { createAIStreamBatcher } from '@/registry/lib/ai-stream-batching';

import { useChat } from '../use-chat';
import { CursorOverlayKit } from './cursor-overlay-kit';
import { MarkdownKit } from './markdown-kit';

export const aiChatPlugin = AIChatPlugin.extend({
  options: {
    chatOptions: {
      api: '/api/ai/command',
      body: {},
    },
  },
  render: {
    afterContainer: AILoadingBar,
    afterEditable: AIMenu,
    node: AIAnchorElement,
  },
  shortcuts: { show: { keys: 'mod+j' } },
  useHooks: ({ editor, getOption }) => {
    useChat();

    const mode = usePluginOption(AIChatPlugin, 'mode');
    const toolName = usePluginOption(AIChatPlugin, 'toolName');
    const insertStreamBatcherRef = useRef<ReturnType<
      typeof createAIStreamBatcher
    > | null>(null);

    if (!insertStreamBatcherRef.current) {
      insertStreamBatcherRef.current = createAIStreamBatcher({
        applyChunk: (chunk, options) => {
          editor.tf.withoutSaving(() => {
            if (!getOption('streaming') && !options?.force) return;

            editor.tf.withScrolling(() => {
              streamInsertChunk(editor, chunk, {
                textProps: {
                  [getPluginType(editor, KEYS.ai)]: true,
                },
              });
            });
          });
        },
      });
    }

    useEffect(
      () => () => {
        insertStreamBatcherRef.current?.reset();
      },
      []
    );

    useChatChunk({
      onChunk: ({ chunk, isFirst, nodes, text: content }) => {
        if (isFirst && mode === 'insert') {
          const { startBlock, startInEmptyParagraph } =
            getInsertPreviewStart(editor);

          editor.getTransforms(BaseAIPlugin).ai.beginPreview({
            originalBlocks:
              startInEmptyParagraph &&
              startBlock &&
              ElementApi.isElement(startBlock)
                ? [cloneDeep(startBlock)]
                : [],
          });

          editor.tf.withoutSaving(() => {
            editor.tf.insertNodes(
              {
                children: [{ text: '' }],
                type: getPluginType(editor, KEYS.aiChat),
              },
              {
                at: PathApi.next(editor.selection!.focus.path.slice(0, 1)),
              }
            );
          });
          editor.setOption(AIChatPlugin, 'streaming', true);
        }

        if (mode === 'insert' && nodes.length > 0) {
          insertStreamBatcherRef.current?.queue({ chunk, isFirst });
        }

        if (toolName === 'edit' && mode === 'chat') {
          withAIBatch(
            editor,
            () => {
              applyAISuggestions(editor, content);
            },
            {
              split: isFirst,
            }
          );
        }
      },
      onFinish: () => {
        insertStreamBatcherRef.current?.flush({ force: true });
        editor.setOption(AIChatPlugin, 'streaming', false);
        resetStreamInsertChunk(editor);
        insertStreamBatcherRef.current?.reset();
      },
    });
  },
});

export const AIKit = [
  ...CursorOverlayKit,
  ...MarkdownKit,
  AIPlugin.withComponent(AILeaf),
  aiChatPlugin,
];
